const STORAGE_ERROR_NAMES = new Set([
  'AbortError',
  'ConstraintError',
  'DataError',
  'InvalidStateError',
  'NotFoundError',
  'QuotaExceededError',
  'TransactionInactiveError',
  'UnknownError',
  'VersionError',
]);

export function isIndexedDbAvailable() {
  return typeof window !== 'undefined' && typeof window.indexedDB !== 'undefined';
}

export function isStorageError(error) {
  if (!error) {
    return false;
  }
  const name = String(error.name || '');
  if (STORAGE_ERROR_NAMES.has(name)) {
    return true;
  }
  const message = String(error.message || '').toLowerCase();
  return message.includes('indexeddb') || message.includes('quota') || message.includes('transaction') || message.includes('storage');
}
